dict.string:
case "$1" in
  habit)    MENU="Habit" ;;
  pomodoro) MENU="Pomodoro" ;;
  matrix)   MENU="Matrix" ;;
esac

osascript \
  -e 'tell application "TickTick" to activate' \
  -e "tell application \"System Events\" to tell process \"TickTick\" to click menu item \"Open \\\"$MENU\\\"\" of menu \"List\" of menu bar 1"
